    if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
      if (CondSI->getCondition() == TrueSI->getCondition() &&
          match(CondSI->getTrueValue(), m_One())) {
        // CondSI: select C1, true, C2
        // TrueSI: select C1, T1, T2
        // SI: select (select C1, true, C2), (select C1, T1, T2), F
        // -> select C1, T1, (select C2, T2, F)
        Value *C1 = CondSI->getCondition();
        Value *C2 = CondSI->getFalseValue();
        Value *T1 = TrueSI->getTrueValue();
        Value *T2 = TrueSI->getFalseValue();
        Value *InnerSel = Builder.CreateSelect(C2, T2, FalseVal, SI.getName() + ".inner", &SI);
        return SelectInst::Create(C1, T1, InnerSel, SI.getName(), nullptr, &SI);
      }
    }
  }

